# Single-table design: Users, Orders, and OrderItems in one table
# PK            | SK                    | entity
# USER#u-123    | METADATA              | user profile
# USER#u-123    | ORDER#o-456           | order summary
# USER#u-123    | ORDER#o-456#ITEM#1    | order item

table = ddb.Table('app')

# Write a user and their order atomically (TransactWrite)
table.meta.client.transact_write(
    TransactItems=[
        {
            'Put': {
                'TableName': 'app',
                'Item': {
                    'PK': 'USER#u-123', 'SK': 'METADATA',
                    'name': 'Alice', 'email': 'alice@example.com'
                }
            }
        },
        {
            'Put': {
                'TableName': 'app',
                'Item': {
                    'PK': 'USER#u-123', 'SK': 'ORDER#o-456',
                    'status': 'PENDING', 'total': 49.99
                }
            }
        }
    ]
)

# Fetch all items for a user (profile + all orders) in one query
response = table.query(
    KeyConditionExpression='PK = :pk',
    ExpressionAttributeValues={':pk': 'USER#u-123'}
)
